using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Shipment>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
        });

        builder.Entity<Shipment>().HasData(
            new Shipment
            {
                Id = 1, TrackingNumber = "SHP-20260501-001",
                Origin = "New York, NY", Destination = "Los Angeles, CA",
                Status = ShipmentStatus.InTransit,
                ShippedDate = new DateTime(2026, 5, 1, 0, 0, 0, DateTimeKind.Utc),
                EstimatedDelivery = new DateTime(2026, 5, 7, 0, 0, 0, DateTimeKind.Utc),
                RecipientName = "Alice Johnson", Description = "Electronics - 2 boxes"
            },
            new Shipment
            {
                Id = 2, TrackingNumber = "SHP-20260502-002",
                Origin = "Chicago, IL", Destination = "Miami, FL",
                Status = ShipmentStatus.Delivered,
                ShippedDate = new DateTime(2026, 4, 28, 0, 0, 0, DateTimeKind.Utc),
                EstimatedDelivery = new DateTime(2026, 5, 3, 0, 0, 0, DateTimeKind.Utc),
                ActualDelivery = new DateTime(2026, 5, 2, 14, 30, 0, DateTimeKind.Utc),
                RecipientName = "Bob Martinez", Description = "Furniture - 1 pallet"
            },
