@page "/"

<PageTitle>ShipmentTracker - Home</PageTitle>

<div class="container">
    <h1 class="mb-4">📦 Shipment Tracker</h1>
    <p class="lead">Track your shipment in real time. Enter your tracking number below.</p>

    <div class="row mb-5">
        <div class="col-md-8">
            <div class="input-group input-group-lg">
                <input type="text" class="form-control" placeholder="e.g. SHP-20260501-001"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                    Track
                </button>
            </div>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    }
    else if (notFound)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>".
        </div>
    }
    else if (shipment is not null)
    {
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">@shipment.TrackingNumber</h5>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <p><strong>From:</strong> @shipment.Origin</p>
                        <p><strong>To:</strong> @shipment.Destination</p>
                        <p><strong>Recipient:</strong> @shipment.RecipientName</p>
                    </div>
                    <div class="col-md-6">
                        <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                        <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy h:mm tt")</p>
                        }
                    </div>
                </div>
                <p class="text-muted mt-2">@shipment.Description</p>
            </div>
        </div>
    }
</div>

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isLoading;
    private bool notFound;
    private ShipmentDto? shipment;

    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searchedNumber = trackingNumber.Trim();
        isLoading = true;
        notFound = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        notFound = shipment is null;
        isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

