<div class="row mb-3">
    <div class="col-md-4">
        <select class="form-select" @bind="selectedStatus">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary w-100" @onclick="LoadShipments">Filter</button>
    </div>
</div>

@if (isLoading)
{
    <div class="spinner-border text-primary" role="status">
        <span class="visually-hidden">Loading...</span>
    </div>
}
else if (shipments is not null)
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td>
                            @if (editingId == s.Id)
                            {
                                <select class="form-select form-select-sm" @bind="newStatus">
                                    @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@st">@st</option>
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                            }
                        </td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (editingId == s.Id)
                            {
                                <button class="btn btn-success btn-sm me-1" @onclick="() => SaveStatus(s.Id)">Save</button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelEdit">Cancel</button>
                            }
                            else
                            {
                                <button class="btn btn-outline-primary btn-sm" @onclick="() => StartEdit(s)">Update</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    @if (shipments.Count == 0)
    {
        <div class="alert alert-info">No shipments match the selected filter.</div>
    }
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger mt-3">@errorMessage</div>
}

