+<div class="row mb-3">
+    <div class="col-md-4">
+        <select class="form-select" @bind="selectedStatus">
+            <option value="">All Statuses</option>
+            @foreach (var s in Enum.GetValues<ShipmentStatus>())
+            {
+                <option value="@s">@s</option>
+            }
+        </select>
+    </div>
+    <div class="col-md-2">
+        <button class="btn btn-primary w-100" @onclick="LoadShipments">Filter</button>
+    </div>
+</div>
+
+@if (isLoading)
+{
+    <div class="spinner-border text-primary" role="status">
+        <span class="visually-hidden">Loading...</span>
+    </div>
+}
+else if (shipments is not null)
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead class="table-dark">
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Origin</th>
+                    <th>Destination</th>
+                    <th>Recipient</th>
+                    <th>Status</th>
+                    <th>Est. Delivery</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var s in shipments)
+                {
+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.Origin</td>
+                        <td>@s.Destination</td>
+                        <td>@s.RecipientName</td>
+                        <td>
+                            @if (editingId == s.Id)
+                            {
+                                <select class="form-select form-select-sm" @bind="newStatus">
+                                    @foreach (var st in Enum.GetValues<ShipmentStatus>())
+                                    {
+                                        <option value="@st">@st</option>
+                                    }
+                                </select>
+                            }
+                            else
+                            {
+                                <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
+                            }
+                        </td>
+                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
+                        <td>
+                            @if (editingId == s.Id)
+                            {
+                                <button class="btn btn-success btn-sm me-1" @onclick="() => SaveStatus(s.Id)">Save</button>
+                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelEdit">Cancel</button>
+                            }
+                            else
+                            {
+                                <button class="btn btn-outline-primary btn-sm" @onclick="() => StartEdit(s)">Update</button>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+
+    @if (shipments.Count == 0)
+    {
+        <div class="alert alert-info">No shipments match the selected filter.</div>
+    }
+}
+
+@if (!string.IsNullOrEmpty(errorMessage))
+{
+    <div class="alert alert-danger mt-3">@errorMessage</div>
+}
+
+@code {
+    private List<ShipmentDto>? shipments;
+    private string selectedStatus = "";
+    private bool isLoading;
+    private int? editingId;
+    private ShipmentStatus newStatus;
+    private string? errorMessage;
+
+    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
+
+    protected override async Task OnInitializedAsync() => await LoadShipments();
+
+    private async Task LoadShipments()
+    {
+        isLoading = true;
+        errorMessage = null;
+        editingId = null;
+        try
+        {
+            shipments = await ShipmentService.GetShipmentsAsync(
+                string.IsNullOrEmpty(selectedStatus) ? null : selectedStatus);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load shipments: {ex.Message}";
+        }
+        isLoading = false;
+    }
+
+    private void StartEdit(ShipmentDto s)
+    {
+        editingId = s.Id;
+        newStatus = s.Status;
+    }
+
+    private void CancelEdit() => editingId = null;
+
+    private async Task SaveStatus(int id)
+    {
+        errorMessage = null;
+        try
+        {
+            await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
+            await LoadShipments();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to update status: {ex.Message}";
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.PickedUp => "bg-secondary",
+        ShipmentStatus.Pending => "bg-warning text-dark",
+        ShipmentStatus.Cancelled => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

